insert into public.map (slug, name, district, category, latitude, longitude, summary, description, vibe_tags, visit_time, route_hint, stamp_reward, hero_label, jam_color, accent_color, is_active) values ('hanbat-forest', '한밭수목원 잼가든', '서구', 'landmark', 36.3671, 127.3886, '산책만 해도 사진이 예쁘게 나오는 대전 대표 힐링 코스', '커다란 온실과 계절 꽃길이 이어져서 첫 방문자도 부담 없이 즐길 수 있어요. 텍스트보다 장면이 먼저 기억나는 장소라 메인 랜딩 포인트로 좋아요.', '["꽃길", "피크닉", "산책"]'::jsonb, '40분 - 1시간 20분', '엑스포다리와 함께 묶으면 노을 코스 완성', '꽃잼 스티커 잠금 해제', 'Bloom Spot', '#ff7aab', '#8fd7ff', true) on conflict (slug) do update set name = excluded.name, district = excluded.district, category = excluded.category, latitude = excluded.latitude, longitude = excluded.longitude, summary = excluded.summary, description = excluded.description, vibe_tags = excluded.vibe_tags, visit_time = excluded.visit_time, route_hint = excluded.route_hint, stamp_reward = excluded.stamp_reward, hero_label = excluded.hero_label, jam_color = excluded.jam_color, accent_color = excluded.accent_color, is_active = excluded.is_active;
insert into public.map (slug, name, district, category, latitude, longitude, summary, description, vibe_tags, visit_time, route_hint, stamp_reward, hero_label, jam_color, accent_color, is_active) values ('expo-bridge', '엑스포다리 선셋뷰', '유성구', 'night', 36.3765, 127.3868, '노을과 강바람을 함께 즐기는 데이트 마커', '해가 내려갈 때 조명이 켜지며 분위기가 확 달라져요. 사진, 산책, 짧은 대화가 모두 가능한 저녁 코스로 추천해요.', '["노을", "데이트", "야경"]'::jsonb, '30분 - 50분', '한밭수목원에서 이동하면 저녁 코스로 매끄러워요', '선셋잼 리본 획득', 'Sunset Spot', '#ff5f8f', '#7e9dff', true) on conflict (slug) do update set name = excluded.name, district = excluded.district, category = excluded.category, latitude = excluded.latitude, longitude = excluded.longitude, summary = excluded.summary, description = excluded.description, vibe_tags = excluded.vibe_tags, visit_time = excluded.visit_time, route_hint = excluded.route_hint, stamp_reward = excluded.stamp_reward, hero_label = excluded.hero_label, jam_color = excluded.jam_color, accent_color = excluded.accent_color, is_active = excluded.is_active;
insert into public.map (slug, name, district, category, latitude, longitude, summary, description, vibe_tags, visit_time, route_hint, stamp_reward, hero_label, jam_color, accent_color, is_active) values ('sungsimdang-culture', '성심당 문화원 골목', '중구', 'food', 36.3276, 127.4271, '빵만이 아니라 대전 감성을 함께 묶어 보여주는 중심 축', '유명세를 외면하지 않되, 주변 골목과 로컬 스팟을 함께 묶어서 성심당만 있는 도시라는 인식을 넓히는 허브로 설계했어요.', '["빵투어", "로컬", "핵심거점"]'::jsonb, '30분 - 1시간', '은행동 골목과 연계하면 체류 시간이 자연스럽게 늘어요', '버터잼 배지 획득', 'Bread Hub', '#ff8d63', '#ffcf69', true) on conflict (slug) do update set name = excluded.name, district = excluded.district, category = excluded.category, latitude = excluded.latitude, longitude = excluded.longitude, summary = excluded.summary, description = excluded.description, vibe_tags = excluded.vibe_tags, visit_time = excluded.visit_time, route_hint = excluded.route_hint, stamp_reward = excluded.stamp_reward, hero_label = excluded.hero_label, jam_color = excluded.jam_color, accent_color = excluded.accent_color, is_active = excluded.is_active;
insert into public.map (slug, name, district, category, latitude, longitude, summary, description, vibe_tags, visit_time, route_hint, stamp_reward, hero_label, jam_color, accent_color, is_active) values ('dunsan-photo', '둔산 소품샵 라인', '서구', 'cafe', 36.3514, 127.3782, '아기자기한 사진과 카페 탐색을 한 번에 즐기는 구간', '짧은 동선 안에 카페, 편집숍, 포토 스팟이 이어져서 계획형 사용자에게 특히 잘 맞아요. 지도에서 여러 곳을 빠르게 비교하기 좋은 영역이에요.', '["소품샵", "포토존", "카페"]'::jsonb, '1시간 - 2시간', '비 오는 날 실내 코스로도 전환이 쉬워요', '솜사탕잼 프레임 지급', 'Cute Loop', '#ff9fd0', '#91a7ff', true) on conflict (slug) do update set name = excluded.name, district = excluded.district, category = excluded.category, latitude = excluded.latitude, longitude = excluded.longitude, summary = excluded.summary, description = excluded.description, vibe_tags = excluded.vibe_tags, visit_time = excluded.visit_time, route_hint = excluded.route_hint, stamp_reward = excluded.stamp_reward, hero_label = excluded.hero_label, jam_color = excluded.jam_color, accent_color = excluded.accent_color, is_active = excluded.is_active;
insert into public.map (slug, name, district, category, latitude, longitude, summary, description, vibe_tags, visit_time, route_hint, stamp_reward, hero_label, jam_color, accent_color, is_active) values ('daecheong-lake', '대청호 레이크뷰', '동구', 'landmark', 36.4803, 127.4784, '도시에서 조금 벗어나 탁 트인 장면을 보는 리프레시 포인트', '드라이브나 짧은 외곽 코스를 찾는 사람에게 어울려요. 대전을 머물기 좋은 도시로 느끼게 하는 장면형 장소라 확장성도 높아요.', '["드라이브", "호수", "힐링"]'::jsonb, '1시간 - 2시간', '오후 출발 반나절 코스로 구성하기 좋아요', '라군잼 배경 지급', 'Lake Escape', '#8bc8ff', '#7ce0cf', true) on conflict (slug) do update set name = excluded.name, district = excluded.district, category = excluded.category, latitude = excluded.latitude, longitude = excluded.longitude, summary = excluded.summary, description = excluded.description, vibe_tags = excluded.vibe_tags, visit_time = excluded.visit_time, route_hint = excluded.route_hint, stamp_reward = excluded.stamp_reward, hero_label = excluded.hero_label, jam_color = excluded.jam_color, accent_color = excluded.accent_color, is_active = excluded.is_active;
insert into public.map (slug, name, district, category, latitude, longitude, summary, description, vibe_tags, visit_time, route_hint, stamp_reward, hero_label, jam_color, accent_color, is_active) values ('galleria-rooftop', '갈마 루프탑 디저트', '서구', 'food', 36.3487, 127.3725, '가볍게 들러도 만족도가 높은 디저트 앵커', '짧은 체류에도 분위기가 살아서 일정 사이사이에 넣기 좋아요. 메인 여정의 휴식 포인트이자 사진용 카드로 활용하기 좋은 장소예요.', '["디저트", "루프탑", "휴식"]'::jsonb, '20분 - 40분', '둔산 소품샵 라인과 함께 묶으면 밀도 높은 반나절 코스', '살구잼 토스트 획득', 'Sweet Break', '#ffb158', '#ff7fa3', true) on conflict (slug) do update set name = excluded.name, district = excluded.district, category = excluded.category, latitude = excluded.latitude, longitude = excluded.longitude, summary = excluded.summary, description = excluded.description, vibe_tags = excluded.vibe_tags, visit_time = excluded.visit_time, route_hint = excluded.route_hint, stamp_reward = excluded.stamp_reward, hero_label = excluded.hero_label, jam_color = excluded.jam_color, accent_color = excluded.accent_color, is_active = excluded.is_active;
