insert into public.feed (position_id, user_id, body, mood, badge) values ((select position_id from public.map where slug = 'hanbat-forest'), 'user-minji', '꽃길 따라 걷다가 바로 사진 찍기 좋아요. 글 길게 안 읽어도 앱 카드만 보고 이동했는데 만족했어요.', '설렘', '첫 방문') on conflict do nothing;
insert into public.feed (position_id, user_id, body, mood, badge) values ((select position_id from public.map where slug = 'expo-bridge'), 'user-jiyoon', '노을 시간 추천해준 게 진짜 좋았어요. 다리 위에서 바람 쐬고 바로 카페로 이동하기 딱이었어요.', '야경픽', '데이트 성공') on conflict do nothing;
insert into public.feed (position_id, user_id, body, mood, badge) values ((select position_id from public.map where slug = 'dunsan-photo'), 'user-seoa', '카테고리만 눌러도 취향 맞는 곳이 보여서 편했어요. 사진 스팟만 빠르게 고르기 좋았습니다.', '친구랑', '포토러버') on conflict do nothing;
insert into public.feed (position_id, user_id, body, mood, badge) values ((select position_id from public.map where slug = 'sungsimdang-culture'), 'user-yujin', '빵만 찍고 끝나는 느낌이 아니라 주변 골목까지 같이 보는 동선이 괜찮았어요.', '혼자서', '로컬탐방') on conflict do nothing;
insert into public.user_stamp (user_id, position_id) values ('jam-demo-user', (select position_id from public.map where slug = 'hanbat-forest')) on conflict (user_id, position_id) do nothing;
insert into public.user_stamp (user_id, position_id) values ('jam-demo-user', (select position_id from public.map where slug = 'sungsimdang-culture')) on conflict (user_id, position_id) do nothing;
